```c
#include <stdio.h>
#include <stdlib.h>

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

int main() {
    int n;
    scanf("%d", &n);

    long long ans = factorial(n) / (factorial(n / 2) * factorial(n / 2));
    ans *= factorial(n / 2 - 1) * factorial(n / 2 - 1);
    ans /= 2;

    printf("%lld\n", ans);
    return 0;
}
```

